const input = $input.first().json;
const rawDump = input.raw_dump;

if (!rawDump || typeof rawDump !== "string") {
  throw new Error("text_pre_processor: raw_dump missing or not a string");
}

const normalized = rawDump
  .replace(/[—–]/g, "-")
  .replace(/[“”‘’]/g, "\"");

const TRANSCRIPT_RE = /Transcript\s+(\d+)[^`]*`([\s\S]+?)`/g;
const GROUND_TRUTH_BY_NUMBER = { 1: "rich", 2: "thin" };

const items = [];
let match;
while ((match = TRANSCRIPT_RE.exec(normalized)) !== null) {
  const transcriptNumber = parseInt(match[1], 10);
  const rawContent = match[2];
  const content = rawContent.split(/\r?\n/).map(l=>l.trim()).filter(l=>l.length>0).join("\n");
  if (content.length === 0) continue;
  const opportunity_id = "OPP-" + String(transcriptNumber).padStart(3, "0");
  const fixture_id = GROUND_TRUTH_BY_NUMBER[transcriptNumber] || "unknown";
  items.push({json: {opportunity_id, transcript_raw: content, _test_meta: {fixture_id, transcript_number: transcriptNumber, utterance_lines: content.split("\n").length, loaded_at: new Date().toISOString()}}});
}
if (items.length === 0) throw new Error("text_pre_processor: no transcripts found");
return items;

// runOnceForEachItem mode: $json is the current item (no need for $input.first())
const body = $json.body ?? $json;
const opportunity_id = body.opportunity_id;
const transcript_raw = body.transcript_raw;
if (!opportunity_id || typeof opportunity_id !== "string") throw new Error("transcript_reader: opportunity_id missing");
if (!transcript_raw || typeof transcript_raw !== "string") throw new Error("transcript_reader: transcript_raw missing");

const LINE_RE = /^\s*\[(\d{1,2}):(\d{2})\]\s*([^:]+?):\s*(.+?)\s*$/;
const utterances = [];
const speakersSet = new Set();
let wordCount = 0;
transcript_raw.split(/\r?\n/).forEach(line => {
  if (!line.trim()) return;
  const m = line.match(LINE_RE); if (!m) return;
  const minutes = parseInt(m[1], 10), seconds = parseInt(m[2], 10);
  const speaker = m[3].trim(), text = m[4].trim();
  utterances.push({line_index: utterances.length, timestamp_raw: '['+m[1].padStart(2,'0')+':'+m[2]+']', timestamp_seconds: minutes*60+seconds, speaker, text});
  speakersSet.add(speaker);
  wordCount += text.split(/\s+/).filter(Boolean).length;
});
if (utterances.length === 0) throw new Error('transcript_reader: no parseable utterances');
const output = {opportunity_id, utterances, metadata: {total_utterances: utterances.length, duration_seconds: utterances[utterances.length-1].timestamp_seconds, speakers: Array.from(speakersSet), estimated_word_count: wordCount, parsed_at: new Date().toISOString()}};
if ($json._test_meta) output._test_meta = $json._test_meta;
return { json: output };

