// extraction_post_normalizer
// Per-OPP: reads agent's output (current item) AND the corresponding loop item from
// loop_over_items (NOT from transcript_reader directly, because transcript_reader
// outputs 2 items and .first() always returns OPP-001).

const input = $input.first().json;

// Pull the current OPP's data from the loop_over_items output (process branch).
// $('loop_over_items').first() returns the current iteration's item.
const loopJson = $('loop_over_items').first().json;
const opportunity_id_from_input = loopJson.opportunity_id;
const utterances = loopJson.utterances || [];
const test_meta = loopJson._test_meta || null;

function safeParse(data) {
  if (data === null || data === undefined) return null;
  if (typeof data === 'object') return data;
  if (typeof data !== 'string') return null;
  try { return JSON.parse(data.trim()); } catch (e) {}
  const fenced = data.replace(/^\s*```json\s*/i,'').replace(/^\s*```\s*/i,'').replace(/\s*```\s*$/i,'').trim();
  try { return JSON.parse(fenced); } catch (e) {}
  const fb = data.indexOf('{'), lb = data.lastIndexOf('}');
  if (fb !== -1 && lb > fb) { try { return JSON.parse(data.substring(fb, lb+1)); } catch (e) {} }
  const fm = data.match(/```json\s*([\s\S]*?)```/i);
  if (fm && fm[1]) { try { return JSON.parse(fm[1].trim()); } catch (e) {} }
  return null;
}
function extractFinalShape(p) {
  if (!p || typeof p !== 'object') return null;
  if (p.type === 'object' && p.properties) return null;
  if (p.abstain !== undefined && p.payload) return p;
  if (p.output && p.output.abstain !== undefined) return p.output;
  if (p.text && p.text.abstain !== undefined) return p.text;
  return null;
}
function truncate(s, max) { if (typeof s !== 'string') return ''; return s.length > max ? s.substring(0, max-3)+'...' : s; }

let rawOutput = '';
if (typeof input.output === 'string') rawOutput = input.output;
else if (typeof input.text === 'string') rawOutput = input.text;
else if (input.output && typeof input.output === 'object') rawOutput = JSON.stringify(input.output);
else rawOutput = JSON.stringify(input);

const direct = extractFinalShape(input);
const parsed = direct ? input : safeParse(rawOutput);
const finalShape = direct || extractFinalShape(parsed);

if (!finalShape) {
  return [{ json: {
    opportunity_id: opportunity_id_from_input,
    draft_payload: {opportunity_id: opportunity_id_from_input, stage: null, amount_usd: null, close_date: null, next_step: null, meddpicc: null, risks: null, last_touch_summary: 'extraction_failed', confidence: 0.05},
    draft_abstain: true, draft_abstain_reason: 'extraction_post_normalizer_failed: no JSON shape',
    draft_reasoning_trace: [], evidence_list: [],
    utterances, sonnet_decision: {abstain: true, confidence: 0.05},
    _test_meta: test_meta, _raw_agent_output: truncate(rawOutput, 1000), _error: true
  }}];
}

const draft = finalShape.payload || {};
draft.opportunity_id = opportunity_id_from_input || draft.opportunity_id;
if (typeof draft.last_touch_summary === 'string') draft.last_touch_summary = truncate(draft.last_touch_summary, 500);

const reasoningTrace = Array.isArray(finalShape.reasoning_trace) ? finalShape.reasoning_trace : [];
const evidence_list = reasoningTrace.filter(r => r && r.field && r.quote && r.timestamp).map(r => ({field: r.field, value: r.value, quote: r.quote, timestamp: r.timestamp}));

return [{ json: {
  opportunity_id: opportunity_id_from_input,
  draft_payload: draft,
  draft_abstain: finalShape.abstain === true,
  draft_abstain_reason: finalShape.abstain_reason || null,
  draft_reasoning_trace: reasoningTrace,
  evidence_list, utterances,
  sonnet_decision: {abstain: finalShape.abstain === true, confidence: typeof draft.confidence === 'number' ? draft.confidence : 0.5},
  _test_meta: test_meta
}}];

