// review_post_normalizer: parses verdict, computes 5-point quality_score.
// Check #4 (tools_invoked) reads the agent's tool_summary field rather than
// $('tool_xxx').all().length — the latter doesn't see ai_tool sub-executions
// in n8n's LangChain agent (sub-executions don't surface as main-flow children).

const input = $input.first().json;
const carry = $('extraction_post_normalizer').first().json;

function safeParse(data) {
  if (data === null || data === undefined) return null;
  if (typeof data === 'object') return data;
  if (typeof data !== 'string') return null;
  try { return JSON.parse(data.trim()); } catch (e) {}
  const fenced = data.replace(/^\s*```json\s*/i,'').replace(/^\s*```\s*/i,'').replace(/\s*```\s*$/i,'').trim();
  try { return JSON.parse(fenced); } catch (e) {}
  const fb = data.indexOf('{'), lb = data.lastIndexOf('}');
  if (fb !== -1 && lb > fb) { try { return JSON.parse(data.substring(fb, lb+1)); } catch (e) {} }
  return null;
}

let rawOutput = '';
if (typeof input.output === 'string') rawOutput = input.output;
else if (typeof input.text === 'string') rawOutput = input.text;
else if (input.output && typeof input.output === 'object') rawOutput = JSON.stringify(input.output);
else rawOutput = JSON.stringify(input);

const verdict = safeParse(rawOutput) || (input.output && typeof input.output === 'object' ? input.output : null);

// --- 5-point quality score ---
let score = 0;
const checks = {};

// Check 1: parseable JSON
checks.parseable = !!verdict;
if (checks.parseable) score++;

// Check 2: valid action
const validActions = ['approve','revise','abstain'];
checks.valid_action = !!verdict && validActions.includes(verdict.action);
if (checks.valid_action) score++;

// Check 3: final_payload has expected keys
checks.payload_shape = !!(verdict && verdict.final_payload && typeof verdict.final_payload === 'object' && 'opportunity_id' in verdict.final_payload && 'last_touch_summary' in verdict.final_payload);
if (checks.payload_shape) score++;

// Check 4: agent reported tool_summary with non-empty content
// Reading the agent's verdict (not n8n node executions, which don't surface ai_tool sub-runs).
let toolSummaryEvidence = 0;
if (verdict && verdict.tool_summary && typeof verdict.tool_summary === 'object') {
  const ts = verdict.tool_summary;
  if (ts.quote_grounding && typeof ts.quote_grounding.all_grounded === 'boolean') toolSummaryEvidence++;
  if (ts.schema && typeof ts.schema.valid === 'boolean') toolSummaryEvidence++;
  if (ts.uncertainty && typeof ts.uncertainty.signal_strength === 'string') toolSummaryEvidence++;
}
checks.tools_invoked = toolSummaryEvidence >= 2;
checks.tool_summary_evidence_count = toolSummaryEvidence;
if (checks.tools_invoked) score++;

// Check 5: internal consistency
let consistent = false;
if (verdict && verdict.action) {
  if (verdict.action === 'abstain') consistent = !!(verdict.reason && verdict.reason.length > 0);
  else if (verdict.action === 'approve') consistent = !!(verdict.final_payload && verdict.final_payload.last_touch_summary);
  else if (verdict.action === 'revise') consistent = !!(verdict.final_payload && typeof verdict.final_payload === 'object');
}
checks.internally_consistent = consistent;
if (checks.internally_consistent) score++;

return [{ json: {
  ...carry,
  review_verdict: verdict,
  quality_score: score,
  quality_checks: checks,
  _raw_review_output: typeof rawOutput === 'string' ? rawOutput.substring(0, 1500) : null
}}];

// finalize_from_review: review verdict accepted. Pass through review's final shape.
const data = $input.first().json;
const verdict = data.review_verdict || {};
const finalPayload = verdict.final_payload || data.draft_payload || {};
const finalTrace = Array.isArray(verdict.final_reasoning_trace) ? verdict.final_reasoning_trace : (Array.isArray(data.draft_reasoning_trace) ? data.draft_reasoning_trace : []);
const action = verdict.action || 'approve';
const abstain = action === 'abstain';
return [{ json: {
  opportunity_id: data.opportunity_id,
  abstain,
  abstain_reason: abstain ? (verdict.reason || data.draft_abstain_reason || 'review_agent abstain') : null,
  payload: finalPayload,
  reasoning_trace: abstain ? [] : finalTrace,
  validation: {
    review_verdict_action: action,
    review_verdict_reason: verdict.reason || null,
    tool_summary: verdict.tool_summary || null,
    quality_checks: data.quality_checks
  },
  meta: {
    processed_at: new Date().toISOString(),
    agent_model: 'claude-haiku-4-5',
    reviewer_model: 'claude-sonnet-4-5',
    path_taken: 'review_agent',
    review_quality_score: data.quality_score,
    tool_invocation_count: data.quality_checks ? data.quality_checks.tool_invocation_count : null,
    _test_meta: data._test_meta
  }
}}];

const grounding = $input.first().json;
const carry = $('review_post_normalizer').first().json;
return [{ json: { ...carry, grounding_result: grounding } }];

const schema = $input.first().json;
const carry = $('merge_grounding').first().json;
return [{ json: { ...carry, schema_result: schema } }];

// merge_validations: deterministic fallback final shape
const uncertainty = $input.first().json;
const carry = $('merge_schema').first().json;
const grounding = carry.grounding_result || {};
const schema = carry.schema_result || {};

const agentAbstained = carry.draft_abstain === true;
const overrideAbstain = uncertainty.overrides_sonnet === true;
const signalAbstain = uncertainty.signal_strength === 'weak' || uncertainty.signal_strength === 'none';
const schemaInvalid = schema.valid === false;
const final_abstain = agentAbstained || overrideAbstain || signalAbstain || schemaInvalid;

let final_abstain_reason = null;
if (agentAbstained) final_abstain_reason = carry.draft_abstain_reason || 'agent self-abstained';
else if (schemaInvalid) final_abstain_reason = 'schema_validation_failed: ' + (schema.errors || []).join('; ');
else if (overrideAbstain) final_abstain_reason = 'uncertainty_override: ' + (uncertainty.reason || '');
else if (signalAbstain) final_abstain_reason = 'low_signal: ' + uncertainty.signal_strength;

const failedFields = grounding.failed_fields || [];
let payload = { ...(carry.draft_payload || {}) };
let reasoning_trace = (carry.draft_reasoning_trace || []).filter(r => !failedFields.includes(r.field));
for (const f of failedFields) {
  const parts = f.split('.');
  if (parts.length === 1) payload[parts[0]] = null;
  else if (parts.length === 2 && payload[parts[0]] && typeof payload[parts[0]] === 'object') {
    payload[parts[0]][parts[1]] = parts[0] === 'meddpicc' ? '' : null;
  }
}

const groundedCount = grounding.grounded_count || 0;
const totalClaims = grounding.total_claims || 0;
const confidence = totalClaims === 0 ? (final_abstain ? 0.85 : 0.5) : Math.max(0.05, Math.min(0.99, groundedCount / totalClaims));
payload.confidence = confidence;

if (final_abstain) {
  payload.stage = null; payload.amount_usd = null; payload.close_date = null;
  payload.next_step = null; payload.meddpicc = null; payload.risks = null;
  if (!payload.last_touch_summary) payload.last_touch_summary = 'No actionable update.';
}

return [{ json: {
  opportunity_id: carry.opportunity_id,
  abstain: final_abstain, abstain_reason: final_abstain_reason,
  payload, reasoning_trace: final_abstain ? [] : reasoning_trace,
  validation: {
    grounding: {all_grounded: grounding.all_grounded, grounded_count: groundedCount, total_claims: totalClaims, failed_fields: failedFields, summary: grounding.summary},
    schema: {valid: schema.valid, errors: schema.errors || [], warnings: schema.warnings || []},
    uncertainty: {signal_strength: uncertainty.signal_strength, should_abstain: uncertainty.should_abstain, overrides_sonnet: uncertainty.overrides_sonnet, flags: uncertainty.flags || [], reason: uncertainty.reason},
    quality_checks: carry.quality_checks
  },
  meta: {
    processed_at: new Date().toISOString(),
    agent_model: 'claude-haiku-4-5',
    reviewer_model: 'deterministic_heuristics_v1',
    path_taken: 'deterministic_fallback',
    review_quality_score: carry.quality_score,
    _test_meta: carry._test_meta
  }
}}];

const all = $input.all();
let updates = 0, abstains = 0, by_path = {review_agent: 0, deterministic_fallback: 0};
for (const item of all) {
  if (item.json.abstain) abstains++; else updates++;
  const path = item.json.meta && item.json.meta.path_taken;
  if (path && by_path[path] !== undefined) by_path[path]++;
}
return [{ json: {
  run_summary: updates + ' update(s), ' + abstains + ' abstain(s)',
  total: all.length, by_path,
  results: all.map(i => i.json)
}}];
